+/// Memory pressure levels used to adapt cache target size.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub enum MemoryPressure {
+    None,
+    Low,
+    Medium,
+    High,
+    Critical,
+}
+
+impl MemoryPressure {
+    #[must_use]
+    fn target_ratio(self) -> f64 {
+        match self {
+            Self::None => 1.0,
+            Self::Low => 0.9,
+            Self::Medium => 0.7,
+            Self::High => 0.5,
+            Self::Critical => 0.2,
+        }
+    }
+}
